import{_ as e,o as t,c as o,U as n}from"./chunks/framework.S9h4scu_.js";const a="/neanes/assets/guide-header-settings-dialog.XpP0fbyC.png",r="/neanes/assets/guide-header-page-number-example-1.jmk3P01i.png",s="/neanes/assets/guide-neume-toolbar-positioning.OBm27odE.png",i="/neanes/assets/guide-neume-positioning-dialog-1.RsgEXy19.png",d="/neanes/assets/guide-neume-positioning-dialog-2.NvxXgsRM.png",P=JSON.parse('{"title":"Advanced","description":"","frontmatter":{},"headers":[],"relativePath":"guide/advanced.md","filePath":"guide/advanced.md"}'),c={name:"guide/advanced.md"},h=n('<h1 id="advanced" tabindex="-1">Advanced <a class="header-anchor" href="#advanced" aria-label="Permalink to &quot;Advanced&quot;">​</a></h1><h2 id="headers-footers" tabindex="-1">Headers &amp; Footers <a class="header-anchor" href="#headers-footers" aria-label="Permalink to &quot;Headers &amp; Footers&quot;">​</a></h2><p>To insert a header or footer, use the file menu: <code>Insert &gt; Headers &amp; Footers &gt; Header</code> or <code>Insert &gt; Headers &amp; Footers &gt; Footer</code>.</p><p>Headers and footers may also be turned on and off in the page setup dialog, whih is accessed through the main menu: <code>File &gt; Page Setup</code>.</p><p><img src="'+a+'" alt="Header Settings Dialog"></p><p>In the page setup dialog, you can control whether the first page has a different header and footer than the rest of the document, as well as whether odd and even pages have different headers.</p><h3 id="page-numbers" tabindex="-1">Page Numbers <a class="header-anchor" href="#page-numbers" aria-label="Permalink to &quot;Page Numbers&quot;">​</a></h3><p>To insert a page number in the header, type <code>$p</code>. When the document is printed, the token <code>$p</code> will be replaced with the correct page number in the header/footer of each page.</p><p><img src="'+r+'" alt="Header Settings Page Number Example"></p><h3 id="other-tokens" tabindex="-1">Other Tokens <a class="header-anchor" href="#other-tokens" aria-label="Permalink to &quot;Other Tokens&quot;">​</a></h3><p>Several other tokens are available. Below is a list of currently supported tokens.</p><table><thead><tr><th>Token</th><th>Description</th></tr></thead><tbody><tr><td><code>$p</code></td><td>Page Number</td></tr><tr><td><code>$n</code></td><td>Number of Pages</td></tr><tr><td><code>$f</code></td><td>File Name (without extension)</td></tr><tr><td><code>$F</code></td><td>File Path</td></tr></tbody></table><h2 id="fine-tuning-neume-positions" tabindex="-1">Fine-tuning Neume Positions <a class="header-anchor" href="#fine-tuning-neume-positions" aria-label="Permalink to &quot;Fine-tuning Neume Positions&quot;">​</a></h2><p>Sometimes the font is unable to properly position neumes when there are multiple supporting neumes. To fix collisions, either double-click the neume or click the <code>Positioning</code> button in the neume toolbar.</p><p><img src="'+s+'" alt="Neume Toolbar Positioning Button"></p><p>This will open the neume positioning dialog.</p><p><img src="'+i+'" alt="Neume Toolbar Positioning Button"></p><p>You can move neumes by either clicking a drag handle (the small blue box near the neume) and moving the mouse, or by editing the values in the <code>Left</code> and <code>Top</code> input boxes.</p><ul><li>To move a neume <strong>left</strong>, <strong>decrease</strong> the <code>Left</code> number.</li><li>To move a neume <strong>right</strong>, <strong>increase</strong> the <code>Left</code> number.</li><li>To move a neume <strong>up</strong>, <strong>decrease</strong> the <code>Top</code> number.</li><li>To move a neume <strong>down</strong>, <strong>increase</strong> the <code>Top</code> number.</li></ul><p>In the below example, we have corrected the collision between the heteron and the dipli.</p><p><img src="'+d+'" alt="Neume Toolbar Positioning Button"></p>',21),l=[h];function p(u,g,m,b,f,_){return t(),o("div",null,l)}const T=e(c,[["render",p]]);export{P as __pageData,T as default};
